import { Link } from 'react-router-dom';
import './style.css';

export default function TodoItem({ id, title, completed, onClick, todo }) {
  return (
    <div className={`todo-card${completed ? ' done' : ''}`} onClick={onClick}>
      <Link to={`/todo/${id}`} state={{ todo }} className="todo-link">
        <div className="todo-copy">
          <h3>{title}</h3>
          <span className={`todo-status${completed ? ' complete' : ''}`}>
            {completed ? 'Completed' : 'Pending'}
          </span>
        </div>
      </Link>
    </div>
  );
}
